<?php
/**
 * SpinWheel Pro — RBAC DB + Code Fix Patch
 * Generated: 20260327_102043
 * ════════════════════════════════════════════════════════
 * What this does:
 *   DB:   ALTERs admin_users to add missing RBAC columns
 *         (display_name, role_id, org_scope_ids, reset_token, reset_expires)
 *         Maps existing 'owner' -> superadmin role automatically
 *   CODE: Fixes PHP syntax errors in 4 files
 *         (users.php, organisation.php, projects.php, migrate_rbac.php)
 *
 * What it does NOT touch:
 *   ✓ config.php (DB credentials safe)
 *   ✓ Existing data (projects, participants, wheel_options, org_groups)
 *   ✓ admin_roles table (already correct)
 *   ✓ All other tables
 *
 * Steps:
 *   1. Upload to web root → visit URL → click Apply
 *   2. Sign out & sign back in
 *   3. DELETE this file
 * ════════════════════════════════════════════════════════
 */
set_time_limit(120);
$ROOT = __DIR__;
$FILE_OK = []; $FILE_ERR = [];
$DB_OK   = []; $DB_ERR   = [];
$RUN = isset($_POST['fix']) && $_POST['fix'] === 'yes';

$scheme = (!empty($_SERVER['HTTPS']) && $_SERVER['HTTPS'] !== 'off') ? 'https' : 'http';
$host   = $_SERVER['HTTP_HOST'] ?? 'localhost';
$doc    = rtrim(str_replace("\\", "/", (string)realpath($_SERVER['DOCUMENT_ROOT'] ?? '')), '/');
$app    = rtrim(str_replace("\\", "/", (string)realpath(__DIR__)), '/');
$sub    = ($doc && strlen($doc) && strpos($app, $doc) === 0) ? substr($app, strlen($doc)) : '';
$URL    = rtrim($scheme . '://' . $host . $sub, '/');

if ($RUN) {

    // ── PART 1: Fix PHP files ─────────────────────────────────────────────────
    $raw     = base64_decode('');
    $payload = json_decode($raw, true);
    if (!$payload) {
        $FILE_ERR[] = 'Payload decode failed.';
    } else {
        foreach ($payload as $rel => $b64) {
            $full = $ROOT . '/' . $rel;
            $dir  = dirname($full);
            $content = base64_decode($b64);
            if (!is_dir($dir) && !mkdir($dir, 0755, true)) { $FILE_ERR[] = "Cannot create: $dir"; continue; }
            if (file_put_contents($full, $content) !== false) $FILE_OK[] = [$rel, strlen($content)];
            else $FILE_ERR[] = "Cannot write: $rel";
        }
    }

    // ── PART 2: DB migration ──────────────────────────────────────────────────
    try {
        require_once $ROOT . '/includes/config.php';
        require_once $ROOT . '/includes/Database.php';
        $db  = Database::getInstance();
        $pdo = $db->getConnection();
        $pdo->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);

        // Check which columns already exist
        $existing = [];
        foreach ($pdo->query("SHOW COLUMNS FROM `admin_users`")->fetchAll(PDO::FETCH_ASSOC) as $col) {
            $existing[] = $col['Field'];
        }

        // Add display_name
        if (!in_array('display_name', $existing)) {
            $pdo->exec("ALTER TABLE `admin_users` ADD COLUMN `display_name` VARCHAR(120) DEFAULT NULL AFTER `username`");
            $DB_OK[] = 'Added admin_users.display_name';
        } else { $DB_OK[] = 'admin_users.display_name already exists'; }

        // Add role_id
        if (!in_array('role_id', $existing)) {
            $pdo->exec("ALTER TABLE `admin_users` ADD COLUMN `role_id` TINYINT UNSIGNED NOT NULL DEFAULT 1 AFTER `password_hash`");
            $DB_OK[] = 'Added admin_users.role_id';
        } else { $DB_OK[] = 'admin_users.role_id already exists'; }

        // Add org_scope_ids
        if (!in_array('org_scope_ids', $existing)) {
            $pdo->exec("ALTER TABLE `admin_users` ADD COLUMN `org_scope_ids` VARCHAR(500) DEFAULT NULL AFTER `role_id`");
            $DB_OK[] = 'Added admin_users.org_scope_ids';
        } else { $DB_OK[] = 'admin_users.org_scope_ids already exists'; }

        // Add reset_token
        if (!in_array('reset_token', $existing)) {
            $pdo->exec("ALTER TABLE `admin_users` ADD COLUMN `reset_token` VARCHAR(64) DEFAULT NULL");
            $DB_OK[] = 'Added admin_users.reset_token';
        } else { $DB_OK[] = 'admin_users.reset_token already exists'; }

        // Add reset_expires
        if (!in_array('reset_expires', $existing)) {
            $pdo->exec("ALTER TABLE `admin_users` ADD COLUMN `reset_expires` DATETIME DEFAULT NULL");
            $DB_OK[] = 'Added admin_users.reset_expires';
        } else { $DB_OK[] = 'admin_users.reset_expires already exists'; }

        // Add updated_at
        if (!in_array('updated_at', $existing)) {
            $pdo->exec("ALTER TABLE `admin_users` ADD COLUMN `updated_at` DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP");
            $DB_OK[] = 'Added admin_users.updated_at';
        } else { $DB_OK[] = 'admin_users.updated_at already exists'; }

        // Map old role ENUM to role_id
        // owner -> 1 (superadmin), admin -> 2, manager -> 3, viewer -> 4
        if (in_array('role', $existing)) {
            $updated = 0;
            $map = ['owner' => 1, 'admin' => 2, 'manager' => 3, 'viewer' => 4];
            foreach ($map as $oldRole => $newId) {
                $rows = $pdo->prepare("UPDATE `admin_users` SET `role_id` = ? WHERE `role` = ? AND `role_id` = 1");
                $rows->execute([$newId, $oldRole]);
                $updated += $rows->rowCount();
            }
            $DB_OK[] = "Mapped old role ENUM to role_id ({$updated} user(s) updated)";
        }

        // Populate display_name from username where null
        $n = $pdo->exec("UPDATE `admin_users` SET `display_name` = `username` WHERE `display_name` IS NULL OR `display_name` = ''");
        if ($n > 0) $DB_OK[] = "Set display_name from username ({$n} user(s))";

        // Add FK if not exists (wrapped — may fail if already exists, that is fine)
        try {
            // Check if FK already exists
            $fks = $pdo->query("SELECT CONSTRAINT_NAME FROM information_schema.TABLE_CONSTRAINTS
                WHERE TABLE_SCHEMA = DATABASE() AND TABLE_NAME = 'admin_users'
                AND CONSTRAINT_TYPE = 'FOREIGN KEY'")->fetchAll(PDO::FETCH_COLUMN);
            if (!in_array('fk_user_role', $fks)) {
                $pdo->exec("ALTER TABLE `admin_users` ADD CONSTRAINT `fk_user_role` FOREIGN KEY (`role_id`) REFERENCES `admin_roles`(`id`)");
                $DB_OK[] = 'Added FK: admin_users.role_id -> admin_roles.id';
            } else {
                $DB_OK[] = 'FK fk_user_role already exists';
            }
        } catch (PDOException $e) {
            $DB_OK[] = 'FK skipped (likely already exists): ' . $e->getMessage();
        }

        // Add index on reset_token if not exists
        try {
            $pdo->exec("ALTER TABLE `admin_users` ADD INDEX `idx_reset` (`reset_token`)");
            $DB_OK[] = 'Added index on reset_token';
        } catch (PDOException $e) { /* already exists */ }

        // Verify final state
        $user = $pdo->query("SELECT id, username, display_name, role_id, status FROM admin_users LIMIT 1")->fetch(PDO::FETCH_ASSOC);
        $DB_OK[] = "Verified: admin user '{$user['username']}' has role_id={$user['role_id']}, status={$user['status']}";

    } catch (PDOException $e) {
        $DB_ERR[] = 'DB error: ' . $e->getMessage();
    } catch (Throwable $e) {
        $DB_ERR[] = 'Error: ' . $e->getMessage();
    }
}

$allOk = $RUN && empty($FILE_ERR) && empty($DB_ERR);
?>
